    "including ",
    "encompassing ",
    "categories of ",
    "category of ",
    "fields of ",
    "seeking ",
    "destination for ",
    "specializes in ",
    "services in "
]

def parse_categories(desc):
    best_start = -1
    best_keyword_len = 0
    for kw in keywords:
        idx = desc.rfind(kw)
        if idx != -1:
            if idx > best_start:
                best_start = idx
                best_keyword_len = len(kw)
    if best_start != -1:
        cat_str = desc[best_start + best_keyword_len:].strip().strip('.')
        if (cat_str.startswith("'") and cat_str.endswith("'")) or (cat_str.startswith('"') and cat_str.endswith('"')):
            cat_str = cat_str[1:-1]
        parts = cat_str.split(',')
        cats = []
        for part in parts:
            part = part.strip()
            if part.lower().startswith('and '):
                part = part[4:].strip()
            if part:
                cats.append(part)
        return cats
    return []

for b in businesses_data:
    bid = b.get('business_id')
    desc = b.get('description', '')
    if bid in review_counts:
        cats = parse_categories(desc)
        cnt = review_counts[bid]
        for cat in cats:
            if cat == "American (New)":
                contributors[bid] = cnt

print("__RESULT__:")
print(json.dumps(contributors))

